const attachmentCreateMutation = `mutation AttachmentCreate($input: AttachmentCreateInput!) {
  attachmentCreate(input: $input) {
    attachment {
      archivedAt
      bodyData
      createdAt
      groupBySource
      id
      metadata
      source
      sourceType
      subtitle
      title
      updatedAt
      url
    }
    lastSyncId
    success
  }
}`

func handleAttachmentCreate(args map[string]any, transport Transport) (map[string]any, error) {
	issueID, err := requireString(args, "issueId")
	if err != nil {
		return nil, err
	}
	title, err := requireString(args, "title")
	if err != nil {
		return nil, err
	}
	url, err := requireString(args, "url")
	if err != nil {
		return nil, err
	}
	input := map[string]any{
		"issueId": issueID,
		"title":   title,
		"url":     url,
	}
	if v, ok := optionalString(args, "commentBody"); ok {
		input["commentBody"] = v
	}
	if v, ok := optionalString(args, "commentBodyData"); ok {
		input["commentBodyData"] = v
	}
	if v, ok := optionalString(args, "createAsUser"); ok {
		input["createAsUser"] = v
	}
	if v, ok := optionalString(args, "displayIconUrl"); ok {
		input["displayIconUrl"] = v
	}
	if v, ok := optionalBool(args, "groupBySource"); ok {
		input["groupBySource"] = v
	}
	if v, ok := optionalString(args, "iconUrl"); ok {
		input["iconUrl"] = v
	}
	if v, ok := optionalString(args, "id"); ok {
		input["id"] = v
	}
	if v, ok := optionalString(args, "metadata"); ok {
		input["metadata"] = v
	}
	if v, ok := optionalString(args, "subtitle"); ok {
		input["subtitle"] = v
	}
	variables := map[string]any{
		"input": input,
	}
	return graphqlCall(transport, attachmentCreateMutation, variables)
}

