const commentCreateMutation = `mutation CommentCreate($input: CommentCreateInput!) {
  commentCreate(input: $input) {
    comment {
      archivedAt
      body
      bodyData
      createdAt
      documentContentId
      editedAt
      hideInLinear
      id
      initiativeId
      initiativeUpdateId
      isArtificialAgentSessionRoot
      issueId
      parentId
      projectId
      projectUpdateId
      quotedText
      reactionData
      resolvedAt
      resolvingCommentId
      threadSummary
      updatedAt
      url
    }
    lastSyncId
    success
  }
}`

func handleCommentCreate(args map[string]any, transport Transport) (map[string]any, error) {
	input := map[string]any{}
	if v, ok := optionalString(args, "body"); ok {
		input["body"] = v
	}
	if v, ok := optionalString(args, "bodyData"); ok {
		input["bodyData"] = v
	}
	if v, ok := optionalString(args, "createAsUser"); ok {
		input["createAsUser"] = v
	}
	if v, ok := optionalBool(args, "createOnSyncedSlackThread"); ok {
		input["createOnSyncedSlackThread"] = v
	}
	if v, ok := optionalString(args, "createdAt"); ok {
		input["createdAt"] = v
	}
	if v, ok := optionalString(args, "displayIconUrl"); ok {
		input["displayIconUrl"] = v
	}
	if v, ok := optionalBool(args, "doNotSubscribeToIssue"); ok {
		input["doNotSubscribeToIssue"] = v
	}
	if v, ok := optionalString(args, "documentContentId"); ok {
		input["documentContentId"] = v
	}
	if v, ok := optionalString(args, "id"); ok {
		input["id"] = v
	}
	if v, ok := optionalString(args, "initiativeId"); ok {
		input["initiativeId"] = v
	}
	if v, ok := optionalString(args, "initiativeUpdateId"); ok {
		input["initiativeUpdateId"] = v
	}
	if v, ok := optionalString(args, "issueId"); ok {
		input["issueId"] = v
	}
	if v, ok := optionalString(args, "parentId"); ok {
		input["parentId"] = v
	}
	if v, ok := optionalString(args, "postId"); ok {
		input["postId"] = v
	}
	if v, ok := optionalString(args, "projectId"); ok {
		input["projectId"] = v
	}
	if v, ok := optionalString(args, "projectUpdateId"); ok {
		input["projectUpdateId"] = v
	}
	if v, ok := optionalString(args, "quotedText"); ok {
		input["quotedText"] = v
	}
	if v, ok := optionalString(args, "subscriberIds"); ok {
		input["subscriberIds"] = v
	}
	variables := map[string]any{
		"input": input,
	}
	return graphqlCall(transport, commentCreateMutation, variables)
}

