const cyclesQuery = `query Cycles($after: String, $before: String, $filter: CycleFilter, $first: Int, $includeArchived: Boolean, $last: Int, $orderBy: PaginationOrderBy) {
  cycles(after: $after, before: $before, filter: $filter, first: $first, includeArchived: $includeArchived, last: $last, orderBy: $orderBy) {
    edges {
      cursor
    }
    nodes {
      archivedAt
      autoArchivedAt
      completedAt
      completedIssueCountHistory
      completedScopeHistory
      createdAt
      currentProgress
      description
      endsAt
      id
      inProgressScopeHistory
      isActive
      isFuture
      isNext
      isPast
      isPrevious
      issueCountHistory
      name
      number
      progress
      progressHistory
      scopeHistory
      startsAt
      updatedAt
    }
    pageInfo {
      endCursor
      hasNextPage
      hasPreviousPage
      startCursor
    }
  }
}`

func handleCycles(args map[string]any, transport Transport) (map[string]any, error) {
	filter := map[string]any{}
	if v, ok := optionalString(args, "and"); ok {
		filter["and"] = v
	}
	if v, ok := optionalString(args, "completedAt"); ok {
		filter["completedAt"] = v
	}
	if v, ok := optionalString(args, "createdAt"); ok {
		filter["createdAt"] = v
	}
	if v, ok := optionalString(args, "endsAt"); ok {
		filter["endsAt"] = v
	}
	if v, ok := optionalString(args, "id"); ok {
		filter["id"] = v
	}
	if v, ok := optionalString(args, "inheritedFromId"); ok {
		filter["inheritedFromId"] = v
	}
	if v, ok := optionalString(args, "isActive"); ok {
		filter["isActive"] = v
	}
	if v, ok := optionalString(args, "isFuture"); ok {
		filter["isFuture"] = v
	}
	if v, ok := optionalString(args, "isInCooldown"); ok {
		filter["isInCooldown"] = v
	}
	if v, ok := optionalString(args, "isNext"); ok {
		filter["isNext"] = v
	}
	if v, ok := optionalString(args, "isPast"); ok {
		filter["isPast"] = v
	}
	if v, ok := optionalString(args, "isPrevious"); ok {
		filter["isPrevious"] = v
	}
	if v, ok := optionalString(args, "issues"); ok {
		filter["issues"] = v
	}
	if v, ok := optionalString(args, "name"); ok {
		filter["name"] = v
	}
	if v, ok := optionalString(args, "number"); ok {
		filter["number"] = v
	}
	if v, ok := optionalString(args, "or"); ok {
		filter["or"] = v
	}
	if v, ok := optionalString(args, "startsAt"); ok {
		filter["startsAt"] = v
	}
	if v, ok := optionalString(args, "team"); ok {
		filter["team"] = v
	}
	if v, ok := optionalString(args, "updatedAt"); ok {
		filter["updatedAt"] = v
	}
	variables := map[string]any{
		"filter": filter,
	}
	if v, ok := optionalString(args, "after"); ok {
		variables["after"] = v
	}
	if v, ok := optionalString(args, "before"); ok {
		variables["before"] = v
	}
	if v, ok := optionalInt(args, "first"); ok {
		variables["first"] = v
	}
	if v, ok := optionalBool(args, "includeArchived"); ok {
		variables["includeArchived"] = v
	}
	if v, ok := optionalInt(args, "last"); ok {
		variables["last"] = v
	}
	if v, ok := optionalString(args, "orderBy"); ok {
		variables["orderBy"] = v
	}
	return graphqlCall(transport, cyclesQuery, variables)
}

