const documentCreateMutation = `mutation DocumentCreate($input: DocumentCreateInput!) {
  documentCreate(input: $input) {
    document {
      archivedAt
      color
      content
      contentState
      createdAt
      documentContentId
      hiddenAt
      icon
      id
      slugId
      sortOrder
      summary
      title
      trashed
      updatedAt
      url
    }
    lastSyncId
    success
  }
}`

func handleDocumentCreate(args map[string]any, transport Transport) (map[string]any, error) {
	title, err := requireString(args, "title")
	if err != nil {
		return nil, err
	}
	input := map[string]any{
		"title": title,
	}
	if v, ok := optionalString(args, "color"); ok {
		input["color"] = v
	}
	if v, ok := optionalString(args, "content"); ok {
		input["content"] = v
	}
	if v, ok := optionalString(args, "cycleId"); ok {
		input["cycleId"] = v
	}
	if v, ok := optionalString(args, "icon"); ok {
		input["icon"] = v
	}
	if v, ok := optionalString(args, "id"); ok {
		input["id"] = v
	}
	if v, ok := optionalString(args, "initiativeId"); ok {
		input["initiativeId"] = v
	}
	if v, ok := optionalString(args, "issueId"); ok {
		input["issueId"] = v
	}
	if v, ok := optionalString(args, "lastAppliedTemplateId"); ok {
		input["lastAppliedTemplateId"] = v
	}
	if v, ok := optionalString(args, "projectId"); ok {
		input["projectId"] = v
	}
	if v, ok := optionalString(args, "releaseId"); ok {
		input["releaseId"] = v
	}
	if v, ok := optionalString(args, "resourceFolderId"); ok {
		input["resourceFolderId"] = v
	}
	if v, ok := optionalFloat(args, "sortOrder"); ok {
		input["sortOrder"] = v
	}
	if v, ok := optionalString(args, "subscriberIds"); ok {
		input["subscriberIds"] = v
	}
	if v, ok := optionalString(args, "teamId"); ok {
		input["teamId"] = v
	}
	variables := map[string]any{
		"input": input,
	}
	return graphqlCall(transport, documentCreateMutation, variables)
}

