const documentUpdateMutation = `mutation DocumentUpdate($id: String!, $input: DocumentUpdateInput!) {
  documentUpdate(id: $id, input: $input) {
    document {
      archivedAt
      color
      content
      contentState
      createdAt
      documentContentId
      hiddenAt
      icon
      id
      slugId
      sortOrder
      summary
      title
      trashed
      updatedAt
      url
    }
    lastSyncId
    success
  }
}`

func handleDocumentUpdate(args map[string]any, transport Transport) (map[string]any, error) {
	id, err := requireString(args, "id")
	if err != nil {
		return nil, err
	}
	input := map[string]any{}
	if v, ok := optionalString(args, "color"); ok {
		input["color"] = v
	}
	if v, ok := optionalString(args, "content"); ok {
		input["content"] = v
	}
	if v, ok := optionalString(args, "cycleId"); ok {
		input["cycleId"] = v
	}
	if v, ok := optionalString(args, "hiddenAt"); ok {
		input["hiddenAt"] = v
	}
	if v, ok := optionalString(args, "icon"); ok {
		input["icon"] = v
	}
	if v, ok := optionalString(args, "initiativeId"); ok {
		input["initiativeId"] = v
	}
	if v, ok := optionalString(args, "issueId"); ok {
		input["issueId"] = v
	}
	if v, ok := optionalString(args, "lastAppliedTemplateId"); ok {
		input["lastAppliedTemplateId"] = v
	}
	if v, ok := optionalString(args, "projectId"); ok {
		input["projectId"] = v
	}
	if v, ok := optionalString(args, "releaseId"); ok {
		input["releaseId"] = v
	}
	if v, ok := optionalString(args, "resourceFolderId"); ok {
		input["resourceFolderId"] = v
	}
	if v, ok := optionalFloat(args, "sortOrder"); ok {
		input["sortOrder"] = v
	}
	if v, ok := optionalString(args, "subscriberIds"); ok {
		input["subscriberIds"] = v
	}
	if v, ok := optionalString(args, "teamId"); ok {
		input["teamId"] = v
	}
	if v, ok := optionalString(args, "title"); ok {
		input["title"] = v
	}
	if v, ok := optionalBool(args, "trashed"); ok {
		input["trashed"] = v
	}
	variables := map[string]any{
		"id":    id,
		"input": input,
	}
	return graphqlCall(transport, documentUpdateMutation, variables)
}

