const documentsQuery = `query Documents($after: String, $before: String, $filter: DocumentFilter, $first: Int, $includeArchived: Boolean, $last: Int, $orderBy: PaginationOrderBy, $sort: [DocumentSortInput!]) {
  documents(after: $after, before: $before, filter: $filter, first: $first, includeArchived: $includeArchived, last: $last, orderBy: $orderBy, sort: $sort) {
    edges {
      cursor
    }
    nodes {
      archivedAt
      color
      content
      contentState
      createdAt
      documentContentId
      hiddenAt
      icon
      id
      slugId
      sortOrder
      summary
      title
      trashed
      updatedAt
      url
    }
    pageInfo {
      endCursor
      hasNextPage
      hasPreviousPage
      startCursor
    }
  }
}`

func handleDocuments(args map[string]any, transport Transport) (map[string]any, error) {
	filter := map[string]any{}
	if v, ok := optionalString(args, "and"); ok {
		filter["and"] = v
	}
	if v, ok := optionalString(args, "createdAt"); ok {
		filter["createdAt"] = v
	}
	if v, ok := optionalString(args, "creator"); ok {
		filter["creator"] = v
	}
	if v, ok := optionalString(args, "cycle"); ok {
		filter["cycle"] = v
	}
	if v, ok := optionalString(args, "id"); ok {
		filter["id"] = v
	}
	if v, ok := optionalString(args, "initiative"); ok {
		filter["initiative"] = v
	}
	if v, ok := optionalString(args, "issue"); ok {
		filter["issue"] = v
	}
	if v, ok := optionalString(args, "or"); ok {
		filter["or"] = v
	}
	if v, ok := optionalString(args, "project"); ok {
		filter["project"] = v
	}
	if v, ok := optionalString(args, "release"); ok {
		filter["release"] = v
	}
	if v, ok := optionalString(args, "slugId"); ok {
		filter["slugId"] = v
	}
	if v, ok := optionalString(args, "team"); ok {
		filter["team"] = v
	}
	if v, ok := optionalString(args, "title"); ok {
		filter["title"] = v
	}
	if v, ok := optionalString(args, "updatedAt"); ok {
		filter["updatedAt"] = v
	}
	sort := map[string]any{}
	if v, ok := optionalString(args, "createdAt"); ok {
		sort["createdAt"] = v
	}
	if v, ok := optionalString(args, "creator"); ok {
		sort["creator"] = v
	}
	if v, ok := optionalString(args, "project"); ok {
		sort["project"] = v
	}
	if v, ok := optionalString(args, "title"); ok {
		sort["title"] = v
	}
	if v, ok := optionalString(args, "updatedAt"); ok {
		sort["updatedAt"] = v
	}
	variables := map[string]any{
		"filter": filter,
		"sort":   sort,
	}
	if v, ok := optionalString(args, "after"); ok {
		variables["after"] = v
	}
	if v, ok := optionalString(args, "before"); ok {
		variables["before"] = v
	}
	if v, ok := optionalInt(args, "first"); ok {
		variables["first"] = v
	}
	if v, ok := optionalBool(args, "includeArchived"); ok {
		variables["includeArchived"] = v
	}
	if v, ok := optionalInt(args, "last"); ok {
		variables["last"] = v
	}
	if v, ok := optionalString(args, "orderBy"); ok {
		variables["orderBy"] = v
	}
	return graphqlCall(transport, documentsQuery, variables)
}

