const favoriteCreateMutation = `mutation FavoriteCreate($input: FavoriteCreateInput!) {
  favoriteCreate(input: $input) {
    favorite {
      archivedAt
      color
      createdAt
      detail
      folderName
      icon
      id
      initiativeTab
      pipelineTab
      predefinedViewType
      projectTab
      sortOrder
      title
      type
      updatedAt
      url
    }
    lastSyncId
    success
  }
}`

func handleFavoriteCreate(args map[string]any, transport Transport) (map[string]any, error) {
	input := map[string]any{}
	if v, ok := optionalString(args, "customViewId"); ok {
		input["customViewId"] = v
	}
	if v, ok := optionalString(args, "customerId"); ok {
		input["customerId"] = v
	}
	if v, ok := optionalString(args, "cycleId"); ok {
		input["cycleId"] = v
	}
	if v, ok := optionalString(args, "dashboardId"); ok {
		input["dashboardId"] = v
	}
	if v, ok := optionalString(args, "documentId"); ok {
		input["documentId"] = v
	}
	if v, ok := optionalString(args, "facetId"); ok {
		input["facetId"] = v
	}
	if v, ok := optionalString(args, "folderName"); ok {
		input["folderName"] = v
	}
	if v, ok := optionalString(args, "id"); ok {
		input["id"] = v
	}
	if v, ok := optionalString(args, "initiativeId"); ok {
		input["initiativeId"] = v
	}
	if v, ok := optionalString(args, "initiativeTab"); ok {
		input["initiativeTab"] = v
	}
	if v, ok := optionalString(args, "issueId"); ok {
		input["issueId"] = v
	}
	if v, ok := optionalString(args, "labelId"); ok {
		input["labelId"] = v
	}
	if v, ok := optionalString(args, "parentId"); ok {
		input["parentId"] = v
	}
	if v, ok := optionalString(args, "pipelineTab"); ok {
		input["pipelineTab"] = v
	}
	if v, ok := optionalString(args, "predefinedViewTeamId"); ok {
		input["predefinedViewTeamId"] = v
	}
	if v, ok := optionalString(args, "predefinedViewType"); ok {
		input["predefinedViewType"] = v
	}
	if v, ok := optionalString(args, "projectId"); ok {
		input["projectId"] = v
	}
	if v, ok := optionalString(args, "projectLabelId"); ok {
		input["projectLabelId"] = v
	}
	if v, ok := optionalString(args, "projectTab"); ok {
		input["projectTab"] = v
	}
	if v, ok := optionalString(args, "pullRequestId"); ok {
		input["pullRequestId"] = v
	}
	if v, ok := optionalString(args, "releaseId"); ok {
		input["releaseId"] = v
	}
	if v, ok := optionalString(args, "releaseNoteId"); ok {
		input["releaseNoteId"] = v
	}
	if v, ok := optionalString(args, "releasePipelineId"); ok {
		input["releasePipelineId"] = v
	}
	if v, ok := optionalFloat(args, "sortOrder"); ok {
		input["sortOrder"] = v
	}
	if v, ok := optionalString(args, "teamId"); ok {
		input["teamId"] = v
	}
	if v, ok := optionalString(args, "userId"); ok {
		input["userId"] = v
	}
	variables := map[string]any{
		"input": input,
	}
	return graphqlCall(transport, favoriteCreateMutation, variables)
}

