const issueLabelsQuery = `query IssueLabels($after: String, $before: String, $filter: IssueLabelFilter, $first: Int, $includeArchived: Boolean, $last: Int, $orderBy: PaginationOrderBy) {
  issueLabels(after: $after, before: $before, filter: $filter, first: $first, includeArchived: $includeArchived, last: $last, orderBy: $orderBy) {
    edges {
      cursor
    }
    nodes {
      archivedAt
      color
      createdAt
      description
      id
      isGroup
      lastAppliedAt
      name
      retiredAt
      updatedAt
    }
    pageInfo {
      endCursor
      hasNextPage
      hasPreviousPage
      startCursor
    }
  }
}`

