func handleIssueUpdated(args map[string]any, transport Transport) (map[string]any, error) {
	filter := map[string]any{}
	if v, ok := optionalString(args, "assigneeId"); ok {
		filter["assigneeId"] = v
	}
	if v, ok := optionalString(args, "parentId"); ok {
		filter["parentId"] = v
	}
	if v, ok := optionalString(args, "projectId"); ok {
		filter["projectId"] = v
	}
	if v, ok := optionalString(args, "stateId"); ok {
		filter["stateId"] = v
	}
	if v, ok := optionalString(args, "teamId"); ok {
		filter["teamId"] = v
	}
	variables := map[string]any{
		"filter": filter,
	}
	return graphqlCall(transport, issueUpdatedSubscription, variables)
}

