func handleProjectCreate(args map[string]any, transport Transport) (map[string]any, error) {
	name, err := requireString(args, "name")
	if err != nil {
		return nil, err
	}
	teamIds, err := requireString(args, "teamIds")
	if err != nil {
		return nil, err
	}
	input := map[string]any{
		"name":    name,
		"teamIds": teamIds,
	}
	if v, ok := optionalString(args, "color"); ok {
		input["color"] = v
	}
	if v, ok := optionalString(args, "content"); ok {
		input["content"] = v
	}
	if v, ok := optionalString(args, "convertedFromIssueId"); ok {
		input["convertedFromIssueId"] = v
	}
	if v, ok := optionalString(args, "description"); ok {
		input["description"] = v
	}
	if v, ok := optionalString(args, "icon"); ok {
		input["icon"] = v
	}
	if v, ok := optionalString(args, "id"); ok {
		input["id"] = v
	}
	if v, ok := optionalString(args, "labelIds"); ok {
		input["labelIds"] = v
	}
	if v, ok := optionalString(args, "lastAppliedTemplateId"); ok {
		input["lastAppliedTemplateId"] = v
	}
	if v, ok := optionalString(args, "leadId"); ok {
		input["leadId"] = v
	}
	if v, ok := optionalString(args, "memberIds"); ok {
		input["memberIds"] = v
	}
	if v, ok := optionalInt(args, "priority"); ok {
		input["priority"] = v
	}
	if v, ok := optionalFloat(args, "prioritySortOrder"); ok {
		input["prioritySortOrder"] = v
	}
	if v, ok := optionalFloat(args, "sortOrder"); ok {
		input["sortOrder"] = v
	}
	if v, ok := optionalString(args, "startDate"); ok {
		input["startDate"] = v
	}
	if v, ok := optionalString(args, "startDateResolution"); ok {
		input["startDateResolution"] = v
	}
	if v, ok := optionalString(args, "statusId"); ok {
		input["statusId"] = v
	}
	if v, ok := optionalString(args, "targetDate"); ok {
		input["targetDate"] = v
	}
	if v, ok := optionalString(args, "targetDateResolution"); ok {
		input["targetDateResolution"] = v
	}
	if v, ok := optionalString(args, "templateId"); ok {
		input["templateId"] = v
	}
	if v, ok := optionalBool(args, "useDefaultTemplate"); ok {
		input["useDefaultTemplate"] = v
	}
	variables := map[string]any{
		"input": input,
	}
	if v, ok := optionalString(args, "slackChannelName"); ok {
		variables["slackChannelName"] = v
	}
	return graphqlCall(transport, projectCreateMutation, variables)
}

