func handleReleases(args map[string]any, transport Transport) (map[string]any, error) {
	filter := map[string]any{}
	if v, ok := optionalString(args, "and"); ok {
		filter["and"] = v
	}
	if v, ok := optionalString(args, "completedAt"); ok {
		filter["completedAt"] = v
	}
	if v, ok := optionalString(args, "createdAt"); ok {
		filter["createdAt"] = v
	}
	if v, ok := optionalString(args, "hasReleaseNotes"); ok {
		filter["hasReleaseNotes"] = v
	}
	if v, ok := optionalString(args, "id"); ok {
		filter["id"] = v
	}
	if v, ok := optionalString(args, "name"); ok {
		filter["name"] = v
	}
	if v, ok := optionalString(args, "or"); ok {
		filter["or"] = v
	}
	if v, ok := optionalString(args, "pipeline"); ok {
		filter["pipeline"] = v
	}
	if v, ok := optionalString(args, "stage"); ok {
		filter["stage"] = v
	}
	if v, ok := optionalString(args, "updatedAt"); ok {
		filter["updatedAt"] = v
	}
	if v, ok := optionalString(args, "version"); ok {
		filter["version"] = v
	}
	sort := map[string]any{}
	if v, ok := optionalString(args, "stage"); ok {
		sort["stage"] = v
	}
	variables := map[string]any{
		"filter": filter,
		"sort":   sort,
	}
	if v, ok := optionalString(args, "after"); ok {
		variables["after"] = v
	}
	if v, ok := optionalString(args, "before"); ok {
		variables["before"] = v
	}
	if v, ok := optionalInt(args, "first"); ok {
		variables["first"] = v
	}
	if v, ok := optionalBool(args, "includeArchived"); ok {
		variables["includeArchived"] = v
	}
	if v, ok := optionalInt(args, "last"); ok {
		variables["last"] = v
	}
	if v, ok := optionalString(args, "orderBy"); ok {
		variables["orderBy"] = v
	}
	return graphqlCall(transport, releasesQuery, variables)
}

