func handleTeam(args map[string]any, transport Transport) (map[string]any, error) {
	id, err := requireString(args, "id")
	if err != nil {
		return nil, err
	}
	variables := map[string]any{
		"id": id,
	}
	return graphqlCall(transport, teamQuery, variables)
}

