func handleTeamCreate(args map[string]any, transport Transport) (map[string]any, error) {
	name, err := requireString(args, "name")
	if err != nil {
		return nil, err
	}
	input := map[string]any{
		"name": name,
	}
	if v, ok := optionalFloat(args, "autoArchivePeriod"); ok {
		input["autoArchivePeriod"] = v
	}
	if v, ok := optionalFloat(args, "autoClosePeriod"); ok {
		input["autoClosePeriod"] = v
	}
	if v, ok := optionalString(args, "autoCloseStateId"); ok {
		input["autoCloseStateId"] = v
	}
	if v, ok := optionalString(args, "color"); ok {
		input["color"] = v
	}
	if v, ok := optionalInt(args, "cycleCooldownTime"); ok {
		input["cycleCooldownTime"] = v
	}
	if v, ok := optionalInt(args, "cycleDuration"); ok {
		input["cycleDuration"] = v
	}
	if v, ok := optionalBool(args, "cycleIssueAutoAssignCompleted"); ok {
		input["cycleIssueAutoAssignCompleted"] = v
	}
	if v, ok := optionalBool(args, "cycleIssueAutoAssignStarted"); ok {
		input["cycleIssueAutoAssignStarted"] = v
	}
	if v, ok := optionalBool(args, "cycleLockToActive"); ok {
		input["cycleLockToActive"] = v
	}
	if v, ok := optionalFloat(args, "cycleStartDay"); ok {
		input["cycleStartDay"] = v
	}
	if v, ok := optionalBool(args, "cyclesEnabled"); ok {
		input["cyclesEnabled"] = v
	}
	if v, ok := optionalFloat(args, "defaultIssueEstimate"); ok {
		input["defaultIssueEstimate"] = v
	}
	if v, ok := optionalString(args, "defaultProjectTemplateId"); ok {
		input["defaultProjectTemplateId"] = v
	}
	if v, ok := optionalString(args, "defaultTemplateForMembersId"); ok {
		input["defaultTemplateForMembersId"] = v
	}
	if v, ok := optionalString(args, "defaultTemplateForNonMembersId"); ok {
		input["defaultTemplateForNonMembersId"] = v
	}
	if v, ok := optionalString(args, "description"); ok {
		input["description"] = v
	}
	if v, ok := optionalBool(args, "groupIssueHistory"); ok {
		input["groupIssueHistory"] = v
	}
	if v, ok := optionalString(args, "icon"); ok {
		input["icon"] = v
	}
	if v, ok := optionalString(args, "id"); ok {
		input["id"] = v
	}
	if v, ok := optionalBool(args, "inheritIssueEstimation"); ok {
		input["inheritIssueEstimation"] = v
	}
	if v, ok := optionalBool(args, "inheritProductIntelligenceScope"); ok {
		input["inheritProductIntelligenceScope"] = v
	}
	if v, ok := optionalBool(args, "inheritSlackAutoCreateProjectChannel"); ok {
		input["inheritSlackAutoCreateProjectChannel"] = v
	}
	if v, ok := optionalBool(args, "inheritWorkflowStatuses"); ok {
		input["inheritWorkflowStatuses"] = v
	}
	if v, ok := optionalBool(args, "issueEstimationAllowZero"); ok {
		input["issueEstimationAllowZero"] = v
	}
	if v, ok := optionalBool(args, "issueEstimationExtended"); ok {
		input["issueEstimationExtended"] = v
	}
	if v, ok := optionalString(args, "issueEstimationType"); ok {
		input["issueEstimationType"] = v
	}
	if v, ok := optionalBool(args, "issueSharingEnabled"); ok {
		input["issueSharingEnabled"] = v
	}
	if v, ok := optionalString(args, "key"); ok {
		input["key"] = v
	}
	if v, ok := optionalString(args, "parentId"); ok {
		input["parentId"] = v
	}
	if v, ok := optionalBool(args, "private"); ok {
		input["private"] = v
	}
	if v, ok := optionalString(args, "productIntelligenceScope"); ok {
		input["productIntelligenceScope"] = v
	}
	if v, ok := optionalBool(args, "requirePriorityToLeaveTriage"); ok {
		input["requirePriorityToLeaveTriage"] = v
	}
	if v, ok := optionalString(args, "setIssueSortOrderOnStateChange"); ok {
		input["setIssueSortOrderOnStateChange"] = v
	}
	if v, ok := optionalBool(args, "slackAutoCreateProjectChannel"); ok {
		input["slackAutoCreateProjectChannel"] = v
	}
	if v, ok := optionalString(args, "timezone"); ok {
		input["timezone"] = v
	}
	if v, ok := optionalBool(args, "triageEnabled"); ok {
		input["triageEnabled"] = v
	}
	if v, ok := optionalFloat(args, "upcomingCycleCount"); ok {
		input["upcomingCycleCount"] = v
	}
	variables := map[string]any{
		"input": input,
	}
	if v, ok := optionalString(args, "copySettingsFromTeamId"); ok {
		variables["copySettingsFromTeamId"] = v
	}
	return graphqlCall(transport, teamCreateMutation, variables)
}

