func handleTeamMembershipCreate(args map[string]any, transport Transport) (map[string]any, error) {
	teamID, err := requireString(args, "teamId")
	if err != nil {
		return nil, err
	}
	userID, err := requireString(args, "userId")
	if err != nil {
		return nil, err
	}
	input := map[string]any{
		"teamId": teamID,
		"userId": userID,
	}
	if v, ok := optionalString(args, "id"); ok {
		input["id"] = v
	}
	if v, ok := optionalBool(args, "owner"); ok {
		input["owner"] = v
	}
	if v, ok := optionalFloat(args, "sortOrder"); ok {
		input["sortOrder"] = v
	}
	variables := map[string]any{
		"input": input,
	}
	return graphqlCall(transport, teamMembershipCreateMutation, variables)
}

