func handleTeams(args map[string]any, transport Transport) (map[string]any, error) {
	filter := map[string]any{}
	if v, ok := optionalString(args, "ancestors"); ok {
		filter["ancestors"] = v
	}
	if v, ok := optionalString(args, "and"); ok {
		filter["and"] = v
	}
	if v, ok := optionalString(args, "createdAt"); ok {
		filter["createdAt"] = v
	}
	if v, ok := optionalString(args, "description"); ok {
		filter["description"] = v
	}
	if v, ok := optionalString(args, "id"); ok {
		filter["id"] = v
	}
	if v, ok := optionalString(args, "issues"); ok {
		filter["issues"] = v
	}
	if v, ok := optionalString(args, "key"); ok {
		filter["key"] = v
	}
	if v, ok := optionalString(args, "members"); ok {
		filter["members"] = v
	}
	if v, ok := optionalString(args, "name"); ok {
		filter["name"] = v
	}
	if v, ok := optionalString(args, "or"); ok {
		filter["or"] = v
	}
	if v, ok := optionalString(args, "parent"); ok {
		filter["parent"] = v
	}
	if v, ok := optionalString(args, "private"); ok {
		filter["private"] = v
	}
	if v, ok := optionalString(args, "releasePipelines"); ok {
		filter["releasePipelines"] = v
	}
	if v, ok := optionalString(args, "retiredAt"); ok {
		filter["retiredAt"] = v
	}
	if v, ok := optionalString(args, "updatedAt"); ok {
		filter["updatedAt"] = v
	}
	variables := map[string]any{
		"filter": filter,
	}
	if v, ok := optionalString(args, "after"); ok {
		variables["after"] = v
	}
	if v, ok := optionalString(args, "before"); ok {
		variables["before"] = v
	}
	if v, ok := optionalInt(args, "first"); ok {
		variables["first"] = v
	}
	if v, ok := optionalBool(args, "includeArchived"); ok {
		variables["includeArchived"] = v
	}
	if v, ok := optionalInt(args, "last"); ok {
		variables["last"] = v
	}
	if v, ok := optionalString(args, "orderBy"); ok {
		variables["orderBy"] = v
	}
	return graphqlCall(transport, teamsQuery, variables)
}

