func handleTemplateCreate(args map[string]any, transport Transport) (map[string]any, error) {
	name, err := requireString(args, "name")
	if err != nil {
		return nil, err
	}
	templateData, err := requireString(args, "templateData")
	if err != nil {
		return nil, err
	}
	type_, err := requireString(args, "type")
	if err != nil {
		return nil, err
	}
	input := map[string]any{
		"name":         name,
		"templateData": templateData,
		"type":         type_,
	}
	if v, ok := optionalString(args, "color"); ok {
		input["color"] = v
	}
	if v, ok := optionalString(args, "description"); ok {
		input["description"] = v
	}
	if v, ok := optionalString(args, "icon"); ok {
		input["icon"] = v
	}
	if v, ok := optionalString(args, "id"); ok {
		input["id"] = v
	}
	if v, ok := optionalString(args, "pipelineId"); ok {
		input["pipelineId"] = v
	}
	if v, ok := optionalFloat(args, "sortOrder"); ok {
		input["sortOrder"] = v
	}
	if v, ok := optionalString(args, "teamId"); ok {
		input["teamId"] = v
	}
	variables := map[string]any{
		"input": input,
	}
	return graphqlCall(transport, templateCreateMutation, variables)
}

